diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..ef65d4adbbeb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3881,6 +3881,7 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+
   // select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
   BinaryOperator *FalseBO;
   if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) && !FalseBO->isIntDivRem()) {
@@ -3900,6 +3901,19 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // Simplify select(C2, select(C1, A, B), select(C1, B, A)) -> select(xor(C1, C2), B, A)
+  if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+    if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (TrueSI->getCondition() == FalseSI->getCondition() &&
+          TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
+          TrueSI->getFalseValue() == FalseSI->getTrueValue()) {
+        Value *XorCond = Builder.CreateXor(CondVal, TrueSI->getCondition());
+        return SelectInst::Create(XorCond, TrueSI->getFalseValue(),
+                                  TrueSI->getTrueValue());
+      }
+    }
+  }
+
   Value *NotCond;
   if (match(CondVal, m_Not(m_Value(NotCond))) &&
       !InstCombiner::shouldAvoidAbsorbingNotIntoSelect(SI)) {
@@ -4081,3 +4095,4 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   return nullptr;
 }
+

